PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>

SELECT ?player ?playerLabel (STR(?caps) AS ?capsStr) (STR(?height) AS ?heightStr)
WHERE {
  ?player wdt:P31 wd:Q5 ;
          wdt:P106 wd:Q3417912 ;
          wdt:P1617 wd:Q234567 ;
          rdfs:label ?playerLabel .
  ?player p:P54 ?teamStatement .
  ?teamStatement ps:P54 wd:Q499328 ;
                 pq:P108 ?caps .
  ?player wdt:P2048 ?height .
  FILTER(LANG(?playerLabel) = "en")
  FILTER(?caps < 200)
  FILTER(?height >= 2.025 && ?height <= 2.035)
}
LIMIT 10

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>

SELECT DISTINCT ?player ?playerLabel
WHERE {
  ?player wdt:P31 wd:Q5;
          wdt:P106 wd:Q3417912 ;
          wdt:P27 wd:Q142 ;
          rdfs:label ?playerLabel.
  ?player p:P54 ?teamMembership.
  ?teamMembership ps:P54 wd:Q499328;
                 pq:P1114 ?caps;
                 pq:P582 ?endDate.
  ?player wdt:P2048 ?height.
  FILTER(LANG(?playerLabel) = "en")
  FILTER(?caps < 200)
  FILTER(?endDate <= NOW())
  FILTER(?height >= 2.02 && ?height <= 2.04)
}
LIMIT 10

